-- Matriz energética Colombia: esquema + datos de muestra.
-- Fact_Generacion: fechas 2020-01-01 a 2020-05-21 (serie diaria). Fact_Costos: anio 2024.
-- El nombre del archivo conserva el rango 2020_2025 como convención del proyecto académico.
CREATE DATABASE IF NOT EXISTS MatrizEnergeticaCol;
USE MatrizEnergeticaCol;

CREATE TABLE Dim_TipoEnergia (
    id_tipo_energia INT PRIMARY KEY,
    fuente VARCHAR(50),
    es_convencional BOOLEAN,
    descripcion TEXT
);


CREATE TABLE Dim_Regulacion (
    id_regulacion INT PRIMARY KEY,
    ley VARCHAR(100),
    incentivo VARCHAR(255),
    pct_ahorro DECIMAL(5,2)
);


CREATE TABLE Dim_Proyecto (
    id_proyecto INT PRIMARY KEY,
    nombre VARCHAR(100),
    depto VARCHAR(100),
    id_tipo INT,
    capacidad_mw DECIMAL(10,2),
    FOREIGN KEY (id_tipo) REFERENCES Dim_TipoEnergia(id_tipo_energia)
);


CREATE TABLE Fact_Generacion (
    id_gen INT AUTO_INCREMENT PRIMARY KEY,
    id_proyecto INT,
    fecha DATE,
    generacion_gwh DECIMAL(12,4),
    factor_planta_pct DECIMAL(5,2),
    FOREIGN KEY (id_proyecto) REFERENCES Dim_Proyecto(id_proyecto)
);


CREATE TABLE Fact_Costos (
    id_costo INT AUTO_INCREMENT PRIMARY KEY,
    id_proyecto INT,
    anio INT,
    lcoe_usd_mwh DECIMAL(10,2),
    capex_musd DECIMAL(12,2),
    opex_musd DECIMAL(12,2),
    FOREIGN KEY (id_proyecto) REFERENCES Dim_Proyecto(id_proyecto)
);


CREATE TABLE Fact_ImpactoAmbiental (
    id_impacto INT AUTO_INCREMENT PRIMARY KEY,
    id_proyecto INT,
    co2_evitado_ton DECIMAL(15,2),
    ahorro_agua_m3 DECIMAL(15,2),
    FOREIGN KEY (id_proyecto) REFERENCES Dim_Proyecto(id_proyecto)
);


CREATE TABLE Fact_Cobertura (
    id_cobertura INT AUTO_INCREMENT PRIMARY KEY,
    id_proyecto INT,
    id_reg INT,
    usuarios INT,
    disponibilidad_pct DECIMAL(5,2),
    FOREIGN KEY (id_proyecto) REFERENCES Dim_Proyecto(id_proyecto),
    FOREIGN KEY (id_reg) REFERENCES Dim_Regulacion(id_regulacion)
);

